def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    # Slide 3 is index 2
    slide = prs.slides[2]
    # Find all text runs that are experiment names by comparing to original
    original_names = ['Norman Triplett Experiment', 'Milgram’s Shock Experiment', 'Leon Festinger studies of Cognitive Dissonance', 'David Hamilton and Robert Gifford (1976)', 'Richard T. La Piere’s hospitality Study']
    corresponding_experiments = ['Social Facilitation', 'Obedience', 'When Prophecy Fails', 'Illusionary Correlation', 'Attitudes Vs Actions']
    # Create pairs of original name and corresponding experiment
    experiment_pairs = list(zip(original_names, corresponding_experiments))

    # Collect all hyperlinked text
    hyperlinked_texts = set()
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for p in shape.text_frame.paragraphs:
            for run in p.runs:
                text = run.text.strip()
                hlink = run.hyperlink.address if hasattr(run, 'hyperlink') else None
                if hlink:
                    hyperlinked_texts.add(text)

    # Check if either the original name or corresponding experiment is linked for each pair
    missing_pairs = []
    for original, corresponding in experiment_pairs:
        if original not in hyperlinked_texts and corresponding not in hyperlinked_texts:
            missing_pairs.append(f"{original} / {corresponding}")

    if missing_pairs:
        reason = f"The following experiment pairs on slide 3 are missing hyperlinks (neither original nor corresponding name is linked): {missing_pairs}" 
        score = 1.0 - len(missing_pairs)/len(experiment_pairs)
        return (reason, max(0.0, score))

    reason = "All experiment name pairs on slide 3 have at least one hyperlinked version (either original name or corresponding experiment name)."
    return (reason, 1.0)

